  function buildVox(src){
    // src = VOX_MODELS 키(문자열) 또는 {pal,data} 모델 객체(디오라마 등 외부 셋도 동일 디코드).
    const m=(typeof src==='string')?VOX_MODELS[src]:src, pal=m.pal, d=m.data, out=[];
    // data는 값당 1글자로 패킹된 문자열(값 = charCodeAt-63). 4글자 = 복셀 1개(x,y,z,palIdx).
    for (let i=0;i<d.length;i+=4) out.push({ x:d.charCodeAt(i)-63, y:d.charCodeAt(i+1)-63, z:d.charCodeAt(i+2)-63, c:pal[d.charCodeAt(i+3)-63] });
    return out;
  }

