    const m=new THREE.MeshStandardMaterial({
      vertexColors:true, color:0xffffff,
      roughness:(partName==='body')?0.42:0.5, metalness:0.05,
    });
    m.name=partName;     // 파트명 보존(검증/누수진단/머티리얼별 식별)
    _octoVCMat[partName]=m;
    return m;
