    //   (에디터 config 값 0.86 등이 매 스테이지마다 덮이는 충돌 방지). 딜리버러블(에디터 미존재)에서만 자동 적용.
    if (window.__ED){ if (typeof buildOctoNums==='function') buildOctoNums(); return; }
