    if (!inst) return null;
    const rs=_queueRowScale(row);
    inst.rotation.set(QUEUE.tiltX, QUEUE.faceY, 0);   // 쿼터뷰 · 뒤에서 보기 (각 문어 제자리 각도; 시점은 큐 카메라 오빗으로)
    inst.position.z=_queueRowZ(row);
