    inst.userData.qi=qi;
    inst.userData.col=col;
    inst.userData.row=row;
    inst.userData.rowScale=rs;     // emerge/pop 애니가 기준으로 삼을 이 줄의 목표 scale(평면 크기, 보정 전)
    inst.userData.baseX=x;
